x_snc_airop_check_definition.check_script:
(function() {
    try {
        if (!gs.tableExists("sn_lg_matter_matter")) {
            return { status: "value_blocker", actualValue: "Required table sn_lg_matter_matter not found", finding: "Legal Matter table is not available. Verify the Legal Service Delivery plugin is active." };
        }
        var ga = new GlideAggregate("sn_lg_matter_matter");
        ga.addAggregate("COUNT");
        ga.query();
        var c = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;
        if (c >= 50) {
            return { status: "ready", actualValue: c + " legal matters", finding: c + " legal matters found. Now Assist LSD has sufficient matter data for AI-assisted legal triage and summarization." };
        } else if (c > 0) {
            return { status: "needs_attention", actualValue: c + " legal matters", finding: c + " legal matter(s) found (target: 50+). Limited matter volume reduces Now Assist LSD AI summarization accuracy." };
        } else {
            return { status: "value_blocker", actualValue: "0 legal matters", finding: "No legal matters found. Now Assist LSD requires matter data for AI-assisted legal triage and summarization." };
        }
    } catch(e) {
        return { status: "needs_validation", actualValue: "Check failed", finding: "Script execution error: " + e.message };
    }
})
